  ('locality-e3452428-moex-00314', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '行政程序法第11條第1項規定，行政機關之管轄權，依其組織法規或其他行政法規定之。此乃下 列那一原則之表現？', '["管轄恆定原則", "管轄法定原則", "依法行政原則", "法律保留原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00315', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '依據公務人員保障法規定之復審程序，下列敘述何者錯誤？', '["非現職人員基於原公務人員身分之公法上財產請求權遭侵害時，亦得提起復審", "公務人員之名譽權生前遭受侵害者，其遺族亦得提起復審", "復審之提起，應自行政處分達到之次日起30日內為之", "復審事件涉及地方自治事項者，公務人員保障暨培訓委員會僅就行政處分之合法性進行審查決定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00316', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於公務人員考績，下列敘述何者正確？', '["年終考績丙等，留原俸級", "年終考績以100分為滿分，分甲、乙、丙、丁、戊五等", "一次記二大功者，晉本俸一級，並給與2個月俸給總額之獎金", "一次記二大過者，停職"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00317', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '依公務人員保障法之規定，關於公務人員之服從義務，下列敘述何者正確？', '["凡長官在其監督範圍內發布之命令，無論是否合法，公務人員皆有服從義務", "長官在其監督範圍內發布之命令，公務人員如認為違反行政法規者，自得拒絕服從", "長官所發布之命令有違反刑事法律者，公務人員無服從之義務", "公務人員認長官之命令違法者，於履行報告義務後，不待長官書面下達，即應服從"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00318', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於公務員懲戒法之適用範圍與對象，下列敘述何者錯誤？', '["非執行職務之違法行為，若嚴重損害政府之信譽亦應受懲戒", "公務員之行為非出於故意或過失者，不受懲戒", "適用對象包括政務人員", "不適用於退休或離職之公務員於任職期間之行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00319', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於行政規則之敘述，下列何者錯誤？', '["行政規則乃為上級機關對於下級機關所為規範機關內部秩序之抽象性規定", "行政規則對於法院並不具拘束力，法院有權直接宣告其無效", "上級機關為協助下級機關行使裁量權，得訂定裁量性行政規則", "有效下達之行政規則，具有拘束下級機關及屬官之效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00320', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於法規命令之敘述，下列何者正確？', '["法規命令之內容應明列其法律授權之依據，不得逾越法律授權之範圍與立法精神，必要時，亦 可再委任下級機關訂定之", "行政機關訂定有關軍事、外交或其他重大事項且涉及國家機密或安全之法規命令，得不依行政 程序法所定程序為之", "行政機關擬訂法規命令時，得依職權採取各種適當方法，將公告內容廣泛周知", "法規命令依法應經上級機關核定者，應於發布後送上級機關核定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00321', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '依司法實務見解，下列何者非屬行政處分？', '["對公務員所為年終考績丙等之核定", "行政機關出借宿舍給所屬公務員", "對公務員作出記大過一次之懲處", "衛生福利部中央健康保險署對於其有全民健康保險特約之醫事服務機構所為之停止特約行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00322', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '依實務見解，行政程序法第98條第3項規定，自處分書送達後1年內聲明不服時，視為於法定 期間內所為之規定，對於下列何者不適用？', '["未受送達行政處分書之利害關係人", "行政處分相對人", "受送達行政處分書之利害關係人", "一般民眾"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00323', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '依行政程序法規定，下列何者非屬行政處分之無效事由？', '["具有重大明顯之瑕疵", "應以證書方式作成而未給予證書", "內容對任何人均屬不能實現", "違反有關土地管轄之規定 30830、31130 31930"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL)
